import os
import re

# Function to check if a function is deprecated (has # @deprecated: comment immediately above)
def is_deprecated(lines, func_line_idx):
    # Check the line immediately above the def
    if func_line_idx > 0:
        line_above = lines[func_line_idx - 1].strip()
        if line_above.startswith('# @deprecated:'):
            return True
    return False

# Function to check if a name is private (starts with _)
def is_private(name):
    return name.startswith('_')

# Process each module
modules = {}
for filename in sorted(os.listdir('.')):
    if not filename.endswith('.py') or filename == 'BROKEN.py':
        continue

    module_name = filename[:-3]  # Remove .py extension

    try:
        with open(filename, 'r', encoding='utf-8') as f:
            lines = f.readlines()
    except UnicodeDecodeError:
        print(f"Skipping {filename} due to UTF-8 decode error")
        continue

    # Find all top-level function definitions
    functions = []
    for i, line in enumerate(lines):
        # Match function definitions at the start of a line (top-level)
        if line.startswith('def '):
            # Extract function name
            match = re.match(r'def\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*\(', line)
            if match:
                func_name = match.group(1)

                # Check if public and not deprecated
                if not is_private(func_name) and not is_deprecated(lines, i):
                    functions.append(func_name)

    if functions:
        modules[module_name] = sorted(functions)

# Generate API.md content
output = []
for module_name in sorted(modules.keys()):
    output.append(f"## {module_name}")
    for func_name in modules[module_name]:
        output.append(f"- {func_name}")
    output.append("")  # Blank line between sections

api_content = '\n'.join(output)

# Write to API.md
with open('API.md', 'w', encoding='utf-8') as f:
    f.write(api_content)

print("API.md created successfully")
print("\nContent:")
print(api_content)
EOF
